import { Component, h, Prop, Element, Event, EventEmitter, State } from '@stencil/core';

@Component({
  tag: 'wdpr-empty-state',
  shadow: true,
})
export class WdprEmptyState {
  @Element() el!: HTMLWdprEmptyStateElement;

  @State() _responsiveSize: 'small' | 'medium' | 'large' = 'medium';

  @Prop({ mutable: true, reflect: true }) size?: 'small' | 'medium' | 'large';
  @Prop() mediaType: 'icon' | 'media' = 'icon';
  @Prop() icon?: string;
  @Prop() mediaSrc?: string;
  @Prop() mediaAlt: string = '';
  @Prop() mediaShape: 'flat' | 'round' = 'flat';
  @Prop() heading!: string;
  @Prop() bodyContent!: string;
  @Prop() showPrimaryButton: boolean = true;
  @Prop() showSecondaryButton: boolean = false;
  @Prop() position: 'inline' | 'stacked' = 'stacked';
  @Prop() primaryActionText: string = 'Label';
  @Prop() secondaryActionText: string = 'Label';

  @Event({ eventName: 'wdprPrimaryClick' }) wdprPrimaryClick!: EventEmitter<void>;
  @Event({ eventName: 'wdprSecondaryClick' }) wdprSecondaryClick!: EventEmitter<void>;

  componentWillLoad() {
    this._setResponsiveSize();
  }

  componentDidLoad() {
    window.addEventListener('resize', this._setResponsiveSize);
  }

  disconnectedCallback() {
    window.removeEventListener('resize', this._setResponsiveSize);
  }

  private _handlePrimaryClick = () => this.wdprPrimaryClick.emit();
  private _handleSecondaryClick = () => this.wdprSecondaryClick.emit();

  private _setResponsiveSize = () => {
    const width = window.innerWidth;
    if (width < 600) {
      this._responsiveSize = 'small';
    } else if (width < 1024) {
      this._responsiveSize = 'medium';
    } else {
      this._responsiveSize = 'large';
    }
  };

  private get _effectiveSize() {
    return this.size ?? this._responsiveSize;
  }

  render() {
    const effectiveAlt = this.mediaAlt || this.heading;
    const size = this._effectiveSize;
    // Force position to 'stacked' when responsiveSize is 'small'
    const effectivePosition = this._responsiveSize === 'small' ? 'stacked' : this.position;

    return (
      <section aria-labelledby="empty-state-heading" class={emptyStateWrapperClasses}>
        <div class={emptyStateMediaWrapperClasses}>
          <slot name="media">
            {this.mediaType === 'icon' && this.icon && (
              <wdpr-icon-library
                icon={this.icon}
                size="xlarge"
                ariaTitle={this.heading}
                decorative={false}
              />
            )}
            {this.mediaType === 'media' && this.mediaSrc && (
              <wdpr-media
                src={this.mediaSrc}
                alt={effectiveAlt}
                shape={this.mediaShape}
                aspect="square"
                class={mediaSizeClasses[size]}
              />
            )}
          </slot>
        </div>
        <div class={emptyStateContentWrapperClasses}>
          <div class={emptyStateTextWrapperClasses}>
            <slot name="heading">
              {this.heading && <h2 id="empty-state-heading" class={emptyStateHeadingClasses[size]}>{this.heading}</h2>}
            </slot>
            <slot name="body">
              {this.bodyContent && <p class={emptyStateBodyClasses}>{this.bodyContent}</p>}
            </slot>
          </div>
          {(this.showPrimaryButton || this.showSecondaryButton) && (
            <div class={emptyStateActionsWrapperClasses(effectivePosition, size)}>
              {effectivePosition === 'stacked'
                ? [
                    <slot name="primary-button">
                      {this.showPrimaryButton && this.primaryActionText && (
                        <wdpr-button
                          type="button"
                          variant="primary"
                          class="w-auto"
                          onWdprClick={this._handlePrimaryClick}
                        >
                          {this.primaryActionText}
                        </wdpr-button>
                      )}
                    </slot>,
                    <slot name="secondary-button">
                      {this.showSecondaryButton && this.secondaryActionText && (
                        <wdpr-button
                          type="button"
                          variant="tertiary"
                          class="w-auto"
                          onWdprClick={this._handleSecondaryClick}
                        >
                          {this.secondaryActionText}
                        </wdpr-button>
                      )}
                    </slot>,
                  ]
                : [
                    <slot name="secondary-button">
                      {this.showSecondaryButton && this.secondaryActionText && (
                        <wdpr-button
                          type="button"
                          variant="tertiary"
                          class="w-auto"
                          onWdprClick={this._handleSecondaryClick}
                        >
                          {this.secondaryActionText}
                        </wdpr-button>
                      )}
                    </slot>,
                    <slot name="primary-button">
                      {this.showPrimaryButton && this.primaryActionText && (
                        <wdpr-button
                          type="button"
                          variant="primary"
                          class="w-auto"
                          onWdprClick={this._handlePrimaryClick}
                        >
                          {this.primaryActionText}
                        </wdpr-button>
                      )}
                    </slot>,
                  ]}
            </div>
          )}
        </div>
      </section>
    );
  }
}

const emptyStateWrapperClasses = 'flex flex-col items-center justify-center text-center mx-auto bg-surface-transparent';
const emptyStateMediaWrapperClasses = 'flex justify-center items-center mb-300';
const emptyStateContentWrapperClasses = 'flex flex-col items-center self-stretch gap-200';
const emptyStateTextWrapperClasses = 'flex flex-col items-center self-stretch gap-025';
const emptyStateHeadingClasses = {
  small: 'heading-small',
  medium: 'title-medium-alt',
  large: 'title-large-alt',
};
const emptyStateBodyClasses = 'body-large text-text-body max-w-prose';
const mediaSizeClasses = {
  small:  'block w-[min(164px,70vw)] aspect-square',
  medium: 'block w-[min(320px,85vw)] aspect-square',
  large:  'block w-[min(424px,90vw)] aspect-square',
};
const emptyStateActionsWrapperClasses = (position: 'inline' | 'stacked', size: 'small' | 'medium' | 'large') => {
  const layout = position === 'inline' ? 'flex-row flex-wrap justify-center' : 'flex-col items-center';
  const gapSize = position === 'inline' ? (size === 'small' ? 'gap-200' : 'gap-300') : 'gap-150';
  
  return `flex ${layout} ${gapSize}`;
};
